// marshalTypesProposalToProposalResponseBody builds a value of type
// *ProposalResponseBody from a value of type *types.Proposal.
func marshalTypesProposalToProposalResponseBody(v *types.Proposal) *ProposalResponseBody {
	res := &ProposalResponseBody{
		ID:                 v.ID,
		Kind:               v.Kind,
		TargetRef:          v.TargetRef,
		CurrentValue:       v.CurrentValue,
		ProposedValue:      v.ProposedValue,
		AppliedValue:       v.AppliedValue,
		Reasoning:          v.Reasoning,
		SourceChatID:       v.SourceChatID,
		Status:             v.Status,
		CreatedAt:          v.CreatedAt,
		AppliedAt:          v.AppliedAt,
		DismissedAt:        v.DismissedAt,
		RolledBackAt:       v.RolledBackAt,
		AppliedByUserID:    v.AppliedByUserID,
		DismissedByUserID:  v.DismissedByUserID,
		RolledBackByUserID: v.RolledBackByUserID,
	}

	return res
}

// marshalTypesMemoryToMemoryResponseBody builds a value of type
// *MemoryResponseBody from a value of type *types.Memory.
func marshalTypesMemoryToMemoryResponseBody(v *types.Memory) *MemoryResponseBody {
	res := &MemoryResponseBody{
		ID:              v.ID,
		Kind:            v.Kind,
		Content:         v.Content,
		SourceChatID:    v.SourceChatID,
		UsefulnessScore: v.UsefulnessScore,
		ExpiresAt:       v.ExpiresAt,
		LastUsedAt:      v.LastUsedAt,
		CreatedAt:       v.CreatedAt,
	}
	if v.Tags != nil {
		res.Tags = make([]string, len(v.Tags))
		for i, val := range v.Tags {
			res.Tags[i] = val
		}
	} else {
		res.Tags = []string{}
	}

	return res
}
